member.example:
Bind the BoxCollider center property using a serialized binder field — the target BoxCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private BoxColliderCenterBinder _center;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _center;
    }


Bind the BoxCollider center property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private BoxCollider _boxCollider;
        
        private BoxColliderCenterBinder Center =>
            new(_boxCollider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _center;
    }

Switch the BoxCollider center between two Vector3 values using a serialized binder field — the target BoxCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private BoxColliderCenterSwitcherBinder _isActive;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }


Switch the BoxCollider center between two Vector3 values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private BoxCollider _boxCollider;
        
        private BoxColliderCenterSwitcherBinder IsActive => new(
            _boxCollider,
            trueValue: new Vector3(0, 1, 0),
            falseValue: Vector3.zero);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }
